import{_ as o,o as i,c as l,ag as a}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"О проекте | Dotfiles (RU)","titleTemplate":":title","description":"Конфигурационные файлы нового поколения, управляемые Chezmoi. Высокопроизводительные, безопасные, AI-нативные.","frontmatter":{"title":"О проекте | Dotfiles","description":"Конфигурационные файлы нового поколения, управляемые Chezmoi. Высокопроизводительные, безопасные, AI-нативные.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"О проекте preview","canonical":"/ru/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"О проекте","pageType":"docs","schemaType":"WebPage","metaTitle":"О проекте - Dotfiles (RU)","permalink":"/ru/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, конфигурация, автоматизация, macos, linux, rust, zellij"}]},"headers":[],"relativePath":"ru/about/index.md","filePath":"ru/about/index.md","lastUpdated":1773010926000}'),d={name:"ru/about/index.md"};function t(c,e,s,r,n,h){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="о-dotfiles-v0-2-495" tabindex="-1">О Dotfiles v0.2.495 <a class="header-anchor" href="#о-dotfiles-v0-2-495" aria-label="Permalink to &quot;О Dotfiles v0.2.495&quot;">​</a></h1><h2 id="введение" tabindex="-1">Введение <a class="header-anchor" href="#введение" aria-label="Permalink to &quot;Введение&quot;">​</a></h2><p>Dotfiles представляет современный стандарт конфигурации окружения. Построен на <strong>Chezmoi</strong> и обеспечивает безопасное, надёжное и кроссплатформенное управление оболочкой, приложениями и секретами.</p><p>В отличие от устаревших dotfiles, полагающихся на сложные Makefile или скрипты символических ссылок, Dotfiles использует шаблонный подход — атомарный и быстрый.</p><h2 id="что-нового-в-v0-2-495" tabindex="-1">Что нового в v0.2.495 <a class="header-anchor" href="#что-нового-в-v0-2-495" aria-label="Permalink to &quot;Что нового в v0.2.495&quot;">​</a></h2><ul><li><strong>Современное ядро</strong>: Замена устаревших Unix-инструментов высокопроизводительными альтернативами на Rust: <ul><li><strong>Atuin</strong> (замена <code>history</code>)</li><li><strong>Yazi</strong> (замена <code>ls</code>/<code>ranger</code>)</li><li><strong>Zellij</strong> (замена <code>tmux</code>)</li><li><strong>Ghostty</strong> (современный GPU-ускоренный терминал)</li><li><strong>NeoVim</strong> (современный редактор на базе Vim)</li></ul></li><li><strong>Нативная безопасность</strong>: Полностью нативная подпись SSH без сторонних агентов.</li><li><strong>Интерактивный режим</strong>: Новая команда <code>dot learn</code> для знакомства с функциями.</li></ul><h2 id="установка" tabindex="-1">Установка <a class="header-anchor" href="#установка" aria-label="Permalink to &quot;Установка&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="проверка" tabindex="-1">Проверка <a class="header-anchor" href="#проверка" aria-label="Permalink to &quot;Проверка&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="основные-команды" tabindex="-1">Основные команды <a class="header-anchor" href="#основные-команды" aria-label="Permalink to &quot;Основные команды&quot;">​</a></h2><ul><li><code>dot apply</code> применяет изменения конфигурации.</li><li><code>dot update</code> обновляет репозиторий и прогревает кэши.</li><li><code>dot doctor</code> проверяет пути, инструменты и состояние оболочки.</li><li><code>dot heal</code> восстанавливает отсутствующее или повреждённое состояние.</li><li><code>dot smoke-test</code> проверяет основные инструментальные цепочки.</li></ul><h2 id="связанные-страницы" tabindex="-1">Связанные страницы <a class="header-anchor" href="#связанные-страницы" aria-label="Permalink to &quot;Связанные страницы&quot;">​</a></h2><ul><li><a href="/ru/aliases/">Алиасы</a></li><li><a href="/ru/functions/">Функции</a></li><li><a href="/ru/paths/">Пути</a></li></ul><h2 id="основные-команды-1" tabindex="-1">Основные команды <a class="header-anchor" href="#основные-команды-1" aria-label="Permalink to &quot;Основные команды&quot;">​</a></h2><p>CLI <code>dot</code> предоставляет 53 команды, организованные по категориям.</p><h3 id="ядро" tabindex="-1">Ядро <a class="header-anchor" href="#ядро" aria-label="Permalink to &quot;Ядро&quot;">​</a></h3><ul><li><code>dot apply</code> — применяет изменения конфигурации.</li><li><code>dot sync</code> — получает последнее состояние репозитория и применяет.</li><li><code>dot update</code> — обновляет репозиторий и прогревает кеши.</li><li><code>dot add</code> — добавляет новые файлы в источник Chezmoi.</li><li><code>dot diff</code> — показывает ожидающие изменения перед применением.</li><li><code>dot status</code> — отображает статус управляемых файлов.</li><li><code>dot remove</code> — снимает файл с управления и удаляет запись источника.</li><li><code>dot cd</code> — открывает оболочку в каталоге источника Chezmoi.</li><li><code>dot edit</code> — открывает управляемый файл в вашем редакторе.</li><li><code>dot clean-cache</code> — очищает временные кеши.</li><li><code>dot prewarm</code> — предварительно заполняет кеши для ускорения запуска оболочки.</li></ul><h3 id="диагностика" tabindex="-1">Диагностика <a class="header-anchor" href="#диагностика" aria-label="Permalink to &quot;Диагностика&quot;">​</a></h3><ul><li><code>dot doctor</code> — проверяет пути, инструменты и состояние оболочки.</li><li><code>dot heal</code> — автоматически исправляет отсутствующее или повреждённое состояние.</li><li><code>dot health</code> — запускает лёгкую проверку работоспособности.</li><li><code>dot verify</code> — проверяет целостность файлов относительно источника.</li><li><code>dot scorecard</code> — выводит оценку качества конфигурации.</li><li><code>dot snapshot</code> — фиксирует текущее состояние для последующего сравнения.</li><li><code>dot smoke-test</code> — полностью проверяет основные цепочки инструментов.</li><li><code>dot chaos</code> — внедряет сбои для тестирования самовосстановления.</li><li><code>dot bundle</code> — экспортирует переносимый пакет конфигурации.</li><li><code>dot rollback</code> — откатывает к предыдущему снимку.</li><li><code>dot drift</code> — обнаруживает несанкционированные изменения в управляемых файлах.</li><li><code>dot history</code> — показывает журнал истории apply/sync.</li><li><code>dot benchmark</code> — измеряет время запуска оболочки.</li><li><code>dot perf</code> — профилирует медленную инициализацию оболочки.</li></ul><h3 id="внешнии-вид" tabindex="-1">Внешний вид <a class="header-anchor" href="#внешнии-вид" aria-label="Permalink to &quot;Внешний вид&quot;">​</a></h3><ul><li><code>dot theme</code> — переключает цветовую схему терминала.</li><li><code>dot wallpaper</code> — устанавливает обои рабочего стола (macOS).</li><li><code>dot fonts</code> — устанавливает или обновляет Nerd Fonts.</li><li><code>dot tune</code> — настраивает плотность интерфейса и стиль приглашения.</li></ul><h3 id="безопасность" tabindex="-1">Безопасность <a class="header-anchor" href="#безопасность" aria-label="Permalink to &quot;Безопасность&quot;">​</a></h3><ul><li><code>dot backup</code> — создаёт зашифрованные резервные копии конфигурации.</li><li><code>dot encrypt-check</code> — проверяет шифрование секретов в состоянии покоя.</li><li><code>dot firewall</code> — настраивает правила межсетевого экрана хоста.</li><li><code>dot telemetry</code> — управляет анонимной телеметрией использования.</li><li><code>dot dns-doh</code> — включает DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — немедленно блокирует экран.</li><li><code>dot usb-safety</code> — ограничивает автоматическое монтирование USB-накопителей.</li></ul><h3 id="секреты" tabindex="-1">Секреты <a class="header-anchor" href="#секреты" aria-label="Permalink to &quot;Секреты&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — инициализирует бэкенд секретов (age / GPG).</li><li><code>dot secrets</code> — показывает зашифрованные записи секретов.</li><li><code>dot secrets-create</code> — создаёт новый зашифрованный секрет.</li><li><code>dot ssh-key</code> — генерирует или ротирует пары SSH-ключей.</li><li><code>dot ssh-cert</code> — запрашивает SSH-сертификат у центра сертификации.</li></ul><h3 id="ии" tabindex="-1">ИИ <a class="header-anchor" href="#ии" aria-label="Permalink to &quot;ИИ&quot;">​</a></h3><ul><li><code>dot ai</code> — открывает интерактивную сессию помощника ИИ.</li><li><code>dot ai-setup</code> — настраивает API-ключи для провайдеров ИИ.</li><li><code>dot ai-query</code> — отправляет одноразовый запрос к модели ИИ.</li><li>Обёртки инструментов ИИ: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="инструменты" tabindex="-1">Инструменты <a class="header-anchor" href="#инструменты" aria-label="Permalink to &quot;Инструменты&quot;">​</a></h3><ul><li><code>dot tools</code> — показывает встроенные CLI-замены и их статус.</li><li><code>dot new</code> — создаёт новый файл псевдонима или функции.</li><li><code>dot sandbox</code> — открывает одноразовую песочницу.</li><li><code>dot keys</code> — показывает текущие привязки клавиш.</li><li><code>dot learn</code> — запускает интерактивный учебник.</li></ul><h3 id="мета" tabindex="-1">Мета <a class="header-anchor" href="#мета" aria-label="Permalink to &quot;Мета&quot;">​</a></h3><ul><li><code>dot upgrade</code> — обновляет Dotfiles до последнего выпуска.</li><li><code>dot packages</code> — показывает установленные пакеты, управляемые Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — выводит информацию о версии или использовании</li></ul>',32)])])}const b=o(d,[["render",t]]);export{p as __pageData,b as default};
